import React, { useState } from "react";
import { loginApi } from "../services/authApi";
import toast from "react-hot-toast";
import { useNavigate } from "react-router-dom";
import "./LoginPage.css"; // Ensure this contains the .glass-card and .input-ring classes!

const LoginPage = () => {
    const navigate = useNavigate();
    const [phoneNumber, setPhoneNumber] = useState("");
    const [password, setPassword] = useState("");
    const [loading, setLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);

    const handleLogin = async (e) => {
        e.preventDefault();

        if (!phoneNumber || !password) {
            toast.error("Please fill all fields");
            return;
        }

        try {
            setLoading(true);

            const response = await loginApi({
                phone_number: phoneNumber,
                password: password,
            });

            const data = response.data;
            console.log(data);

            localStorage.setItem("access", data.access);
            localStorage.setItem("refresh", data.refresh);

            toast.success("Login successful");
            navigate("/");
        } catch (error) {
            console.log("FULL ERROR:", error);
            console.log("RESPONSE:", error.response);
            console.log(JSON.stringify(error.response?.data, null, 2));
            toast.error("Login failed");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="bg-surface text-on-surface font-body-md min-h-screen flex flex-col relative overflow-hidden">
            {/* Background Elements for Premium Feel */}
            <div className="absolute inset-0 z-0 overflow-hidden pointer-events-none">
                <div className="absolute -top-1/4 -right-1/4 w-[800px] h-[800px] rounded-full bg-primary-fixed/20 blur-[100px]"></div>
                <div className="absolute -bottom-1/4 -left-1/4 w-[600px] h-[600px] rounded-full bg-surface-container-high/40 blur-[80px]"></div>
            </div>

            {/* Main Content Area */}
            <div className="flex-grow flex items-center justify-center p-md md:p-lg lg:p-xl relative z-10 w-full max-w-container-max mx-auto">
                <div className="w-full max-w-[420px]">
                    {/* Auth Card */}
                    <div className="glass-card rounded-xl p-lg md:p-xl flex flex-col gap-lg">
                        {/* Header / Brand */}
                        <div className="flex flex-col items-center text-center mb-sm">
                            <div className="w-12 h-12 bg-primary rounded-lg flex items-center justify-center mb-md shadow-sm">
                                <span className="material-symbols-outlined text-on-primary" data-icon="local_shipping" data-weight="fill" style={{ fontVariationSettings: "'FILL' 1" }}>
                                    local_shipping
                                </span>
                            </div>
                            <h1 className="font-headline-md text-headline-md text-on-surface mb-xs">Welcome back</h1>
                            <p className="font-body-md text-body-md text-on-surface-variant">Sign in to LoadLink Operations</p>
                        </div>

                        {/* Form */}
                        <form className="flex flex-col gap-md" onSubmit={handleLogin}>
                            {/* Phone Input */}
                            <div className="flex flex-col gap-xs">
                                <label className="font-label-md text-label-md text-on-surface" htmlFor="phone">Phone Number</label>
                                <div className="relative flex items-center bg-surface-bright border border-outline-variant rounded-lg input-ring transition-shadow h-12">
                                    <div className="flex items-center px-sm border-r border-outline-variant h-full bg-surface-container-lowest rounded-l-lg cursor-pointer hover:bg-surface-container-low transition-colors">
                                        <span className="font-body-md text-body-md text-on-surface mr-xs">+1</span>
                                        <span className="material-symbols-outlined text-outline text-[16px]" data-icon="arrow_drop_down">arrow_drop_down</span>
                                    </div>
                                    <input 
                                        className="flex-grow bg-transparent border-none focus:ring-0 px-md font-body-md text-body-md text-on-surface h-full placeholder:text-outline/70 rounded-r-lg" 
                                        id="phone" 
                                        placeholder="(555) 000-0000" 
                                        required 
                                        type="tel" 
                                        value={phoneNumber}
                                        onChange={(e) => setPhoneNumber(e.target.value)}
                                    />
                                </div>
                            </div>

                            {/* Password Input */}
                            <div className="flex flex-col gap-xs">
                                <div className="flex justify-between items-center">
                                    <label className="font-label-md text-label-md text-on-surface" htmlFor="password">Password</label>
                                    <a className="font-label-md text-label-md text-primary hover:text-primary-container transition-colors" href="#">Forgot Password?</a>
                                </div>
                                <div className="relative flex items-center bg-surface-bright border border-outline-variant rounded-lg input-ring transition-shadow h-12">
                                    <span className="material-symbols-outlined absolute left-md text-outline" data-icon="lock">lock</span>
                                    <input 
                                        className="w-full bg-transparent border-none focus:ring-0 pl-10 pr-10 font-body-md text-body-md text-on-surface h-full placeholder:text-outline/70 rounded-lg" 
                                        id="password" 
                                        placeholder="Enter your password" 
                                        required 
                                        type={showPassword ? "text" : "password"} 
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                    />
                                    <button 
                                        aria-label="Toggle password visibility" 
                                        className="absolute right-md text-outline hover:text-on-surface transition-colors flex items-center justify-center" 
                                        type="button"
                                        onClick={() => setShowPassword(!showPassword)}
                                    >
                                        <span className="material-symbols-outlined text-[20px]" data-icon={showPassword ? "visibility_off" : "visibility"}>
                                            {showPassword ? "visibility_off" : "visibility"}
                                        </span>
                                    </button>
                                </div>
                            </div>

                            {/* Action Button */}
                            <button 
                                className="w-full bg-primary text-on-primary font-title-lg text-title-lg h-12 rounded-lg mt-sm hover:bg-primary-container transition-colors flex items-center justify-center shadow-sm relative overflow-hidden group disabled:opacity-70 disabled:cursor-not-allowed" 
                                type="submit"
                                disabled={loading}
                            >
                                <span className="relative z-10 flex items-center gap-sm">
                                    {loading ? "Logging in..." : "Login"}
                                    {!loading && <span className="material-symbols-outlined text-[18px]" data-icon="arrow_forward">arrow_forward</span>}
                                </span>
                                <div className="absolute inset-0 bg-white/20 opacity-0 group-active:opacity-100 transition-opacity"></div>
                            </button>
                        </form>

                        {/* Divider */}
                        <div className="flex items-center gap-md my-xs">
                            <div className="h-px bg-outline-variant flex-grow"></div>
                            <span className="font-label-sm text-label-sm text-outline-variant uppercase">or</span>
                            <div className="h-px bg-outline-variant flex-grow"></div>
                        </div>

                        {/* Secondary Actions */}
                        <div className="flex flex-col gap-sm text-center">
                            <p className="font-body-md text-body-md text-on-surface-variant">
                                Don't have an account?{" "}
                                <a className="font-title-lg text-body-md text-primary hover:text-primary-container transition-colors" href="#">Request Access</a>
                            </p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Global Footer */}
            <footer className="w-full p-md lg:px-xl relative z-10 border-t border-outline-variant/30 mt-auto bg-surface-container-lowest/50 backdrop-blur-sm">
                <div className="max-w-container-max mx-auto flex flex-col md:flex-row justify-between items-center gap-md">
                    <div className="flex items-center gap-sm text-on-surface-variant">
                        <span className="font-label-sm text-label-sm">© 2024 LoadLink Operations. All rights reserved.</span>
                    </div>
                    <div className="flex items-center gap-lg">
                        <a className="font-label-md text-label-md text-on-surface-variant hover:text-on-surface transition-colors" href="#">Privacy Policy</a>
                        <a className="font-label-md text-label-md text-on-surface-variant hover:text-on-surface transition-colors" href="#">Terms of Service</a>
                        <div className="flex items-center gap-xs ml-md text-on-surface-variant hover:text-on-surface cursor-pointer transition-colors">
                            <span className="material-symbols-outlined text-[16px]" data-icon="language">language</span>
                            <span className="font-label-md text-label-md">EN (US)</span>
                            <span className="material-symbols-outlined text-[16px]" data-icon="arrow_drop_down">arrow_drop_down</span>
                        </div>
                    </div>
                </div>
            </footer>
        </div>
    );
};

export default LoginPage;

import React from "react";

const AuthLayout = ({ children }) => {
  return (
    <div className="min-h-screen bg-slate-50 flex justify-center items-center px-4">
      {children}
    </div>
  );
};

export default AuthLayout;
